/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  /** Suggested chess piece. Non-null only when chessPiece was absent in the request. */
  suggestedChessPiece?: string | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

// ── Reconcile Assist types ─────────────────────────────────────────────────

export interface ReconcileAssistRequest {
  planId: string;
  userId: string;
}

export interface CommitOutcomeSuggestion {
  commitId: string;
  commitTitle: string;
  suggestedOutcome: string;
  rationale: string;
}

export interface CarryForwardRecommendation {
  commitId: string;
  commitTitle: string;
  rationale: string;
}

export interface ReconcileAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  likelyOutcomes: CommitOutcomeSuggestion[];
  draftSummary?: string | null;
  carryForwardRecommendations: CarryForwardRecommendation[];
}

// ── RCDO Suggest types ────────────────────────────────────────────────────────

export interface RcdoSuggestRequest {
  planId: string;
  userId: string;
  /** Commit title used for semantic matching (required). */
  title: string;
  description?: string | undefined;
  chessPiece?: string | undefined;
}

export interface RcdoSuggestResponse {
  aiAvailable: boolean;
  /** True when a high-confidence (≥ 0.7) match was found. */
  suggestionAvailable: boolean;
  /** Stored suggestion id (null when unavailable or below threshold). */
  suggestionId?: string | null;
  /** Suggested RCDO node id. */
  suggestedRcdoNodeId?: string | null;
  /** Display title of the suggested node. */
  rcdoTitle?: string | null;
  /** Confidence score [0.0, 1.0]. */
  confidence?: number;
  /** Human-readable rationale for the suggestion. */
  rationale?: string | null;
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── Manager AI Summary types ──────────────────────────────────────────────────

export interface ManagerAiSummaryResponse {
  aiAvailable: boolean;
  /** Stored suggestion id for feedback (null when unavailable). */
  suggestionId?: string | null;
  teamId: string;
  weekStart: string;
  /** Prose summary of the team week. Null when aiAvailable=false. */
  summaryText?: string | null;
  /** RCDO branch titles with highest planned commitment this week. */
  topRcdoBranches: string[];
  /** Unresolved exception ids (cited objects). */
  unresolvedExceptionIds: string[];
  /** Textual carry-forward patterns (cited from plan data). */
  carryForwardPatterns: string[];
  /** Work item ids for King/Queen commits currently BLOCKED (cited objects). */
  criticalBlockedItemIds: string[];
  modelVersion?: string | null;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /**
     * Convenience helper for freeform "describe → structure" commit creation.
     * Sends the freeform text as currentTitle and omits chessPiece so the backend
     * can infer suggestedChessPiece.
     */
    commitFromFreeform: (
      planId: string,
      userId: string,
      freeformText: string,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", {
        planId,
        userId,
        currentTitle: freeformText,
      }),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/reconcile-assist — get reconciliation suggestions. */
    reconcileAssist: (
      request: ReconcileAssistRequest,
    ): Promise<ReconcileAssistResponse> =>
      client.post("/ai/reconcile-assist", request),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),

    /**
     * POST /api/ai/rcdo-suggest — suggest a primary RCDO node for a commit
     * being authored. Only returns a suggestion when confidence ≥ 0.7.
     * Never auto-links — caller must present and allow user to accept/dismiss.
     */
    rcdoSuggest: (request: RcdoSuggestRequest): Promise<RcdoSuggestResponse> =>
      client.post("/ai/rcdo-suggest", request),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-summary —
     * AI-generated manager team summary for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamAiSummary: (
      teamId: string,
      weekStart: string,
    ): Promise<ManagerAiSummaryResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-summary`,
        { headers: actorHeader },
      ),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * React hooks for AI API endpoints.
 */
import { useMemo, useState, useEffect, useRef } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createAiApi, type AiApi, type AiStatusResponse, type PlanRiskSignalsResponse, type ReconcileAssistResponse, type ManagerAiSummaryResponse } from "./aiApi.js";

/** Returns a stable AiApi instance bound to the current user's auth token. */
export function useAiApi(): AiApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createAiApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Fetches the AI provider status. */
export function useAiStatus(): QueryState<AiStatusResponse> {
  const api = useAiApi();
  return useQuery<AiStatusResponse>("ai-status", () => api.getStatus());
}

/** Fetches risk signals for a specific plan. */
export function useRiskSignals(
  planId: string | null,
): QueryState<PlanRiskSignalsResponse> {
  const api = useAiApi();
  return useQuery<PlanRiskSignalsResponse>(
    `risk-signals-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getRiskSignals(planId);
    },
    { enabled: planId != null },
  );
}

/**
 * Fetches the AI-generated manager team summary for the given team and week.
 *
 * @param teamId    team UUID string, or `null` to skip fetching
 * @param weekStart ISO date string (YYYY-MM-DD)
 */
export function useManagerAiSummary(
  teamId: string | null,
  weekStart: string,
): QueryState<ManagerAiSummaryResponse> {
  const api = useAiApi();
  return useQuery<ManagerAiSummaryResponse>(
    `manager-ai-summary-${teamId ?? "none"}-${weekStart}`,
    () => {
      if (!teamId) return Promise.reject(new Error("No team ID"));
      return api.getTeamAiSummary(teamId, weekStart);
    },
    { enabled: teamId != null },
  );
}

/**
 * Auto-fetches AI reconciliation suggestions when a plan enters RECONCILING
 * state. Runs once per planId (tracked by ref). Falls back silently if AI
 * is unavailable — callers must handle `data === undefined`.
 *
 * @param planId       Plan UUID string, or null/undefined when not yet known.
 * @param userId       Authenticated user ID for the reconcile-assist request.
 * @param enabled      Set to `true` only when the plan is in RECONCILING state.
 */
export function useAutoReconcileAssist(
  planId: string | null | undefined,
  userId: string,
  enabled: boolean,
): { data: ReconcileAssistResponse | undefined; loading: boolean; error: string | null } {
  const aiApi = useAiApi();
  const [data, setData] = useState<ReconcileAssistResponse | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  // Track which planId we've already fetched for so we don't re-fetch on re-renders.
  const fetchedForRef = useRef<string | null>(null);

  useEffect(() => {
    if (!enabled || !planId) return;
    if (fetchedForRef.current === planId) return;
    fetchedForRef.current = planId;

    let cancelled = false;
    setLoading(true);
    setError(null);

    aiApi
      .reconcileAssist({ planId, userId })
      .then((response) => {
        if (cancelled) return;
        if (response.aiAvailable) {
          setData(response);
        }
        setLoading(false);
      })
      .catch(() => {
        if (cancelled) return;
        // Graceful silent fallback — AI unavailable or errored.
        setError("AI suggestions unavailable");
        setLoading(false);
      });

    return () => {
      cancelled = true;
    };
    // aiApi is a new object each render but is memoised inside useAiApi by authToken.
    // Intentionally omitting it from deps to avoid re-fetching on unrelated renders.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [planId, userId, enabled]);

  return { data, loading, error };
}

/**
 * RAG (Retrieval-Augmented Generation) API client functions.
 * Covers the semantic query endpoint and AI insight retrieval endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface RagQueryRequest {
  question: string;
  teamId?: string;
  userId?: string;
}

export interface RagSource {
  entityType: string;
  entityId: string;
  weekStartDate?: string;
  snippet?: string;
}

export interface RagQueryResponse {
  aiAvailable: boolean;
  answer?: string;
  sources?: RagSource[];
  confidence?: number;
  suggestionId?: string;
}

export interface InsightCard {
  suggestionId: string;
  insightText: string;
  severity: string;
  sourceEntityIds: string[];
  actionSuggestion: string;
  createdAt: string;
}

export interface InsightListResponse {
  aiAvailable: boolean;
  insights: InsightCard[];
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createRagApi(client: ApiClient, _actorUserId: string) {
  return {
    /**
     * POST /api/ai/query — execute a semantic RAG query against indexed planning
     * data. Returns an AI-synthesised answer with source citations.
     */
    submitQuery: (req: RagQueryRequest): Promise<RagQueryResponse> =>
      client.post("/ai/query", req),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-insights — retrieve persisted
     * TEAM_INSIGHT rows for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamInsights: (
      teamId: string,
      weekStart: string,
    ): Promise<InsightListResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-insights`,
      ),

    /**
     * GET /api/plans/{id}/ai-insights — retrieve persisted PERSONAL_INSIGHT rows
     * for the given plan.
     *
     * @param planId plan UUID string
     */
    getPlanInsights: (planId: string): Promise<InsightListResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/ai-insights`),
  };
}

export type RagApi = ReturnType<typeof createRagApi>;

/**
 * TypeScript types for Plan and Commit API request/response payloads.
 * Mirror the backend DTO records from PlanController / CommitService.
 */

export type PlanState = "DRAFT" | "LOCKED" | "RECONCILING" | "RECONCILED";

export type ChessPiece =
  | "KING"
  | "QUEEN"
  | "ROOK"
  | "BISHOP"
  | "KNIGHT"
  | "PAWN";

export type CommitOutcome =
  | "ACHIEVED"
  | "PARTIALLY_ACHIEVED"
  | "NOT_ACHIEVED"
  | "CANCELED";

/** Valid Fibonacci-scale estimate point values (mirrors shared/constants.ts). */
export type EstimatePoints = 1 | 2 | 3 | 5 | 8;
export const VALID_ESTIMATE_POINTS: EstimatePoints[] = [1, 2, 3, 5, 8];

/** Plan header — mirrors PlanResponse Java record. */
export interface PlanResponse {
  readonly id: string;
  readonly ownerUserId: string;
  readonly teamId: string;
  /** ISO date: yyyy-MM-dd (Monday of the plan week). */
  readonly weekStartDate: string;
  readonly state: PlanState;
  /** ISO datetime — manual-lock deadline. */
  readonly lockDeadline: string;
  /** ISO datetime — reconciliation deadline. */
  readonly reconcileDeadline: string;
  readonly capacityBudgetPoints: number;
  readonly compliant: boolean;
  readonly systemLockedWithErrors: boolean;
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Single commit — mirrors CommitResponse Java record. */
export interface CommitResponse {
  readonly id: string;
  readonly planId: string;
  readonly ownerUserId: string;
  readonly title: string;
  readonly description?: string;
  readonly chessPiece: ChessPiece;
  readonly priorityOrder: number;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
  readonly outcome?: CommitOutcome;
  readonly outcomeNotes?: string;
  readonly carryForwardStreak: number;
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Combined response — mirrors PlanWithCommitsResponse Java record. */
export interface PlanWithCommitsResponse {
  readonly plan: PlanResponse;
  readonly commits: CommitResponse[];
  readonly totalPoints: number;
}

/** POST /api/plans request body — mirrors CreatePlanRequest Java record. */
export interface GetOrCreatePlanPayload {
  readonly userId: string;
  readonly weekStartDate?: string;
}

/** POST /api/plans/{planId}/commits request body — mirrors CreateCommitRequest. */
export interface CreateCommitPayload {
  readonly title: string;
  readonly chessPiece: ChessPiece;
  readonly description?: string;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
}

/**
 * PUT /api/plans/{planId}/commits/{commitId} request body.
 * Null/omitted fields are treated as "no-op" by the backend.
 */
export interface UpdateCommitPayload {
  readonly title?: string;
  readonly chessPiece?: ChessPiece;
  readonly description?: string;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
}

// ── Lock types ────────────────────────────────────────────────────────────────

/** A single hard-validation failure returned by POST /api/plans/{id}/lock. */
export interface LockValidationError {
  readonly field: string;
  readonly message: string;
}

/**
 * Response from POST /api/plans/{id}/lock.
 * success=false → errors contains the hard validation failures.
 */
export interface LockResponse {
  readonly success: boolean;
  readonly plan: PlanWithCommitsResponse | null;
  readonly errors: LockValidationError[];
}

// ── Scope-change types ────────────────────────────────────────────────────────

export type ScopeChangeCategory =
  | "COMMIT_ADDED"
  | "COMMIT_REMOVED"
  | "ESTIMATE_CHANGED"
  | "CHESS_PIECE_CHANGED"
  | "RCDO_CHANGED"
  | "PRIORITY_CHANGED";

export type ScopeChangeAction = "ADD" | "REMOVE" | "EDIT";

/** Single scope-change event — mirrors ScopeChangeEventResponse Java record. */
export interface ScopeChangeEventResponse {
  readonly id: string;
  readonly planId: string;
  readonly commitId: string | null;
  readonly category: ScopeChangeCategory;
  readonly changedByUserId: string | null;
  readonly reason: string;
  readonly previousValue: string | null;
  readonly newValue: string | null;
  readonly createdAt: string;
}

/** Timeline response — mirrors ScopeChangeTimelineResponse Java record. */
export interface ScopeChangeTimelineResponse {
  readonly events: ScopeChangeEventResponse[];
  readonly managerExceptions: unknown[];
}

/** Request body for POST /api/plans/{id}/scope-changes. */
export interface ScopeChangePayload {
  readonly action: ScopeChangeAction;
  readonly reason: string;
  readonly commitId?: string;
  readonly commitData?: CreateCommitPayload;
  readonly changes?: UpdateCommitPayload;
}

// ── Reconciliation types ──────────────────────────────────────────────────────

/** Per-commit reconciliation view — mirrors ReconcileCommitView Java record. */
export interface ReconcileCommitView {
  readonly commitId: string;
  readonly currentTitle: string;
  readonly currentChessPiece: ChessPiece;
  readonly currentEstimatePoints: number | null;
  readonly currentOutcome: CommitOutcome | null;
  readonly currentOutcomeNotes: string | null;
  /** Baseline snapshot values (null for post-lock-added commits). */
  readonly baselineSnapshot: Record<string, unknown> | null;
  readonly scopeChanges: ScopeChangeEventResponse[];
  readonly linkedTicketStatus: string | null;
  readonly addedPostLock: boolean;
  readonly removedPostLock: boolean;
}

/** Full reconciliation view response — mirrors ReconciliationViewResponse. */
export interface ReconciliationViewResponse {
  readonly plan: PlanResponse;
  readonly commits: ReconcileCommitView[];
  readonly baselineTotalPoints: number;
  readonly currentTotalPoints: number;
  readonly commitCount: number;
  readonly outcomesSetCount: number;
}

/** Request body for PUT /api/plans/{id}/commits/{commitId}/outcome. */
export interface SetOutcomePayload {
  readonly outcome: CommitOutcome;
  readonly notes?: string | undefined;
}

// ── Carry-forward types ───────────────────────────────────────────────────────

export type CarryForwardReason =
  | "BLOCKED_BY_DEPENDENCY"
  | "SCOPE_EXPANDED"
  | "REPRIORITIZED"
  | "RESOURCE_UNAVAILABLE"
  | "TECHNICAL_OBSTACLE"
  | "EXTERNAL_DELAY"
  | "UNDERESTIMATED"
  | "STILL_IN_PROGRESS";

/** Request body for POST /api/plans/{planId}/commits/{commitId}/carry-forward. */
export interface CarryForwardPayload {
  readonly targetWeekStart: string;
  readonly reason: CarryForwardReason;
  readonly reasonText?: string | undefined;
}

