		}

		allResults.add(evalResult);
		log.info("Eval result: {}", evalResult);
		assertThat(schemaValid).as("Schema validation for case %s", evalCase.id()).isTrue();
	}

	// ── Risk Signal Evaluation ────────────────────────────────────────────

	Stream<EvalCase> riskSignalCases() throws Exception {
